// Inspect the Discord webhook response and route to success or failure.
const response = $input.item.json;
const alert = $('Format Discord Embed').item.json;

const statusCode = response._statusCode || response.statusCode || null;
const hasError = !!response.error || !!response.message || (statusCode && statusCode >= 400);

if (hasError) {
  const errMsg = response.message
    ? (typeof response.message === 'string' ? response.message : JSON.stringify(response.message)).slice(0, 300)
    : response.error
      ? (typeof response.error === 'string' ? response.error : JSON.stringify(response.error).slice(0, 300))
      : `HTTP ${statusCode || 'unknown'}`;
  return [{ json: {
    alert_id:         alert.alert_id,
    topic_slug:       alert.topic_slug,
    date_key:         alert.date_key,
    item_id:          alert.item_id || null,
    status:           'failed',
    platform_post_id: null,
    error_message:    errMsg
  } }];
}

const postId = response.id || null;
return [{ json: {
  alert_id:         alert.alert_id,
  topic_slug:       alert.topic_slug,
  date_key:         alert.date_key,
  item_id:          alert.item_id || null,
  status:           'published',
  platform_post_id: postId,
  error_message:    null
} }];

// Build a social_publish_log entry for Discord alert delivery.
const r = $input.item.json;
return [{ json: {
  _d1_sql: `INSERT INTO social_publish_log
    (topic_slug, date_key, asset_type, source_type, source_id, platform, post_type,
     status, platform_post_id, error_message, attempt, created_at, updated_at)
  VALUES (?, ?, 'story', 'alert', ?, 'discord', 'embed', ?, ?, ?, 1,
    strftime('%Y-%m-%dT%H:%M:%SZ','now'),
    strftime('%Y-%m-%dT%H:%M:%SZ','now')
  )`,
  _d1_params: [
    r.topic_slug,
    r.date_key,
    r.item_id || null,
    r.status || 'published',
    r.platform_post_id || null,
    r.error_message || null
  ],
  ...r
} }];
